```ts
import { Effect, Console } from "effect";

interface FileHandle { readonly path: string; readonly fd: number }

const openFile = (path: string): Effect.Effect<FileHandle, never, never> =>
  Effect.sync(() => ({ path, fd: Math.floor(Math.random() * 1_000_000) }));

const closeFile = (h: FileHandle): Effect.Effect<void> =>
  Console.log(`[close] ${h.path} (fd=${h.fd})`);

// acquireRelease returns Effect<A, E, Scope>; Effect.scoped eliminates Scope.
const fileResource = (path: string) =>
  Effect.acquireRelease(openFile(path), (h) => closeFile(h));

const program = Effect.scoped(
  Effect.gen(function* () {
    const h = yield* fileResource("/tmp/data.txt");
    yield* Console.log(`[use] reading ${h.path}`);
    return h.path;
  })
);

Effect.runPromise(program).then((r) => console.log("done:", r));
```

`Effect.acquireRelease` registers the finalizer in the current `Scope`. `Effect.scoped` closes that scope once the inner effect finishes, so the release runs even if the read step fails.

