import { Effect, Console } from "effect";

interface DbConn { readonly id: number; readonly close: () => void }

const connect = (): Effect.Effect<DbConn> =>
  Effect.sync(() => ({ id: Date.now(), close: () => console.log("disconnected") }));

const disconnect = (c: DbConn): Effect.Effect<void> =>
  Effect.sync(() => c.close());

// The pair: acquire + release.
const conn = Effect.acquireRelease(connect(), (c) => disconnect(c));

const query = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* conn;
    yield* Console.log(`SELECT 1 on conn ${c.id}`);
    return 1 as const;
  })
);

Effect.runPromise(query);
```

Without `Effect.scoped`, the effect still requires `Scope` in its `R` channel and cannot be executed directly. `scoped` closes the scope and runs the release regardless of outcome.

```ts
import { Effect, Data, Console } from "effect";

class ConnectError extends Data.TaggedError("ConnectError")<{ readonly host: string }> {}
class RequestError extends Data.TaggedError("RequestError")<{ readonly status: number }> {}

interface HttpClient { readonly host: string; readonly get: (p: string) => Effect.Effect<string, RequestError> }

const openClient = (host: string): Effect.Effect<HttpClient, ConnectError> =>
  host === "" ? Effect.fail(new ConnectError({ host })) : Effect.succeed({
    host,
    get: (p) => p.startsWith("/") ? Effect.succeed(`ok ${host}${p}`) : Effect.fail(new RequestError({ status: 400 })),
  });

const closeClient = (c: HttpClient): Effect.Effect<void> =>
  Console.log(`[http] closing ${c.host}`);

const clientResource = (host: string) =>
  Effect.acquireRelease(openClient(host), (c) => closeClient(c));

const program: Effect.Effect<string, ConnectError | RequestError, never> = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* clientResource("api.example.com");
    return yield* c.get("/users/1");
  })
);

Effect.runPromise(program).then(console.log);
```

Only the acquisition can fail with `ConnectError`; usage can fail with `RequestError`. Scope eliminates once `Effect.scoped` wraps the whole generator.

Effect.acquireRelease builds an `Effect<A, E, Scope>`: the finalizer is registered against the ambient `Scope` requirement. Effect.scoped supplies that scope and guarantees the release runs once the inner effect finishes — success, failure, or interruption.

