```

Because `Effect.scoped` wraps the generator, the lock is always released — even if the critical section throws.

```ts
import { Effect, Console } from "effect";

interface Handle { readonly id: number }

const open = (): Effect.Effect<Handle> => Effect.sync(() => ({ id: 42 }));
const close = (h: Handle): Effect.Effect<void> => Console.log(`close ${h.id}`);
const use = (h: Handle): Effect.Effect<string> => Effect.succeed(`used ${h.id}`);

// Effect equivalent of try/finally: acquireRelease + scoped
const handle = Effect.acquireRelease(open(), (h) => close(h));

const program = Effect.scoped(
  Effect.gen(function* () {
    const h = yield* handle;
    return yield* use(h);
  })
);

Effect.runPromise(program).then(console.log);
```

The finalizer semantics are stronger than `try/finally`: interruption (timeout, racer winning) also triggers release.

```ts
import { Effect, Schedule, Console } from "effect";

interface Conn { readonly id: number }

const connect = Effect.sync((): Conn => ({ id: 1 }));
const disconnect = (c: Conn) => Console.log(`disconnect ${c.id}`);

const conn = Effect.acquireRelease(connect, (c) => disconnect(c));

let attempts = 0;
const flakyQuery = (c: Conn): Effect.Effect<string, Error> =>
  Effect.suspend(() => {
    attempts += 1;
    return attempts < 2 ? Effect.fail(new Error("flaky")) : Effect.succeed(`row@${c.id}`);
  });

const program = Effect.scoped(
  Effect.gen(function* () {
    const c = yield* conn;
    return yield* Effect.retry(flakyQuery(c), Schedule.recurs(3));
  })
);

Effect.runPromise(program).then(console.log);
```

Retries live *inside* the scoped block, so the connection is held across attempts and released once all retries succeed or exhaust.

```ts
import { Effect, Console, Fiber } from "effect";

interface Socket { readonly port: number }

const openSocket = Effect.sync((): Socket => ({ port: 9000 }));
const closeSocket = (s: Socket) => Console.log(`shutdown ${s.port}`);

const socket = Effect.acquireRelease(openSocket, (s) => closeSocket(s));

const serve = Effect.scoped(
  Effect.gen(function* () {
    const s = yield* socket;
    yield* Console.log(`listening on ${s.port}`);
    yield* Effect.never;
  })
);

const runWithInterrupt = Effect.gen(function* () {
  const fiber = yield* Effect.fork(serve);
  yield* Effect.sleep("20 millis");
  yield* Fiber.interrupt(fiber);
});

Effect.runPromise(runWithInterrupt);
```

`Effect.scoped` treats interruption like any other exit — the finalizer runs. That is why acquireRelease is safer than manual try/finally.

```ts
import { Effect, Console, Ref } from "effect";

interface Tx { readonly id: string; readonly status: Ref.Ref<"open" | "committed"> }

const beginTx: Effect.Effect<Tx> = Effect.gen(function* () {
  const status = yield* Ref.make<"open" | "committed">("open");
  return { id: `tx-${Date.now()}`, status };
});

const finishTx = (tx: Tx): Effect.Effect<void> =>
  Effect.gen(function* () {
    const s = yield* Ref.get(tx.status);
    yield* s === "committed" ? Console.log(`COMMIT ${tx.id}`) : Console.log(`ROLLBACK ${tx.id}`);
  });

const transaction = Effect.acquireRelease(beginTx, (tx) => finishTx(tx));

const writeAndCommit = Effect.scoped(
  Effect.gen(function* () {
    const tx = yield* transaction;
    yield* Console.log(`INSERT ... in ${tx.id}`);
    yield* Ref.set(tx.status, "committed");
    return "ok" as const;
  })
);

Effect.runPromise(writeAndCommit).then(console.log);
```

The release reads the tx's status Ref — if the body set it to `committed`, commit; otherwise (failure, interruption) roll back.

