```ts
import { Effect, Data, Console, Duration } from "effect";

class Timeout extends Data.TaggedError("Timeout")<{ readonly ms: number }> {}

const slowFetch: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("500 millis");
  return "payload";
});

const timeoutFail = (ms: number): Effect.Effect<never, Timeout> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new Timeout({ ms }));
  });

const program: Effect.Effect<string, Timeout> = Effect.race(slowFetch, timeoutFail(200));

Effect.runPromise(Effect.either(program)).then((r) => Console.log(r));
```

`Effect.race` takes the first successful *or* failing completion; whichever side wins, the other is automatically interrupted.

```ts
import { Effect, Fiber } from "effect";

const leftE: Effect.Effect<number> = Effect.succeed(21);
const rightE: Effect.Effect<number> = Effect.succeed(21);

const program = Effect.gen(function* () {
  const f1 = yield* Effect.fork(leftE);
  const f2 = yield* Effect.fork(rightE);
  const a = yield* Fiber.join(f1);
  const b = yield* Fiber.join(f2);
  return a + b;
});

Effect.runPromise(program).then((n) => console.log("sum:", n));
```

`Effect.fork` returns `Effect<Fiber<A, E>, never, R>` — forking never fails, only the fiber itself can. `Fiber.join` awaits completion and re-exposes the `A/E` channels.

```ts
import { Effect, Data, Duration } from "effect";

class Unavailable extends Data.TaggedError("Unavailable")<{ readonly name: string }> {}

const provider = (name: string, delay: Duration.Duration, ok: boolean): Effect.Effect<string, Unavailable> =>
  Effect.gen(function* () {
    yield* Effect.sleep(delay);
    return ok ? `from ${name}` : yield* Effect.fail(new Unavailable({ name }));
  });

const program: Effect.Effect<string, Unavailable> = Effect.raceAll([
  provider("us-east", Duration.millis(80), true),
  provider("eu-west", Duration.millis(40), true),
  provider("ap-south", Duration.millis(120), true),
]);

