```

Unlike a bare Promise, the returned `Fiber` can be interrupted at any time, freeing the resources it holds.

```ts
import { Effect, Fiber } from "effect";

const a: Effect.Effect<number> = Effect.gen(function* () {
  yield* Effect.sleep("20 millis");
  return 10;
});
const b: Effect.Effect<number> = Effect.gen(function* () {
  yield* Effect.sleep("30 millis");
  return 32;
});

const program = Effect.gen(function* () {
  const fa = yield* Effect.fork(a);
  const fb = yield* Effect.fork(b);
  const ra = yield* Fiber.join(fa);
  const rb = yield* Fiber.join(fb);
  return [ra, rb] as const;
});

Effect.runPromise(program).then(([x, y]) => console.log(x, y));
```

The fork/join form lets you keep references to the fibres (for later interrupt) where `Effect.all` doesn't.

```ts
import { Effect, Fiber, Console, Duration } from "effect";

const worker = (name: string, ms: number): Effect.Effect<string> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return `done:${name}`;
  }).pipe(Effect.onInterrupt(() => Console.log(`[interrupt] ${name}`)));

const program: Effect.Effect<string> = Effect.gen(function* () {
  const fa = yield* Effect.fork(worker("A", 30));
  const fb = yield* Effect.fork(worker("B", 90));
  // Manual race: whichever finishes first, interrupt the other.
  return yield* Effect.race(Fiber.join(fa), Fiber.join(fb));
});

Effect.runPromise(program).then((r) => console.log(r));
```

`Effect.onInterrupt` gives the loser a chance to log (or flush) before it is fully cancelled.

```ts
import { Effect, Data, Duration } from "effect";

class ProbeFail extends Data.TaggedError("ProbeFail")<{ readonly url: string }> {}

const probe = (url: string, ms: number, ok: boolean): Effect.Effect<string, ProbeFail> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return ok ? url : yield* Effect.fail(new ProbeFail({ url }));
  });

const program: Effect.Effect<string, ProbeFail> = Effect.raceAll([
  probe("https://a", 70, false),
  probe("https://b", 40, true),
  probe("https://c", 55, true),
  probe("https://d", 90, false),
]);

Effect.runPromise(Effect.either(program)).then(console.log);
```

`raceAll` resolves to the first *successful* completion; remaining probes are interrupted.

`Effect.fork` creates a child fibre supervised by the *current* fibre's scope — if the parent exits, the child is interrupted. `Effect.forkDaemon` forks against the global scope so the fibre outlives the parent.

```ts
import { Effect, Fiber, Console } from "effect";

const beat = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("tick");
    yield* Effect.sleep("40 millis");
  })
);

const program = Effect.gen(function* () {
  const hb = yield* Effect.fork(beat);
  yield* Effect.sleep("90 millis");
  yield* Fiber.interrupt(hb);
  yield* Console.log("parent done");
});

Effect.runPromise(program);
```

Because `hb` is a supervised fork, even if we forget to interrupt it, program exit cancels it automatically.

```ts
import { Effect, Data, Duration } from "effect";

class Boom extends Data.TaggedError("Boom")<{ readonly which: string }> {}

const ok = (ms: number): Effect.Effect<string, Boom> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return "ok";
  });

const bad = (ms: number, tag: string): Effect.Effect<string, Boom> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new Boom({ which: tag }));
  });

// Effect.all with unbounded concurrency short-circuits on first failure
// and interrupts the other fibres.
const program: Effect.Effect<readonly string[], Boom> = Effect.all(
  [ok(80), bad(40, "x"), ok(60)],
  { concurrency: "unbounded" }
);

Effect.runPromise(Effect.either(program)).then(console.log);
```

For first-error short-circuit across many effects prefer `Effect.all(..., { concurrency })`; use `raceAll` when you want the *first success* instead.

```ts
import { Effect, Duration } from "effect";

interface CacheHit { readonly _tag: "cache"; readonly value: string }
interface NetHit { readonly _tag: "net"; readonly value: string; readonly ms: number }
type Hit = CacheHit | NetHit;

const cacheHit: Effect.Effect<Hit> = Effect.gen(function* () {
  yield* Effect.sleep(Duration.millis(25));
  return { _tag: "cache", value: "cached" } as const;
});

const netHit: Effect.Effect<Hit> = Effect.gen(function* () {
  yield* Effect.sleep(Duration.millis(80));
  return { _tag: "net", value: "fresh", ms: 80 } as const;
});

const program: Effect.Effect<Hit> = Effect.race(cacheHit, netHit);

Effect.runPromise(program).then((h) => {
  if (h._tag === "cache") console.log("hit cache:", h.value);
  else console.log(`fresh in ${h.ms}ms: ${h.value}`);
});
```

By funnelling both branches through a shared `Hit` union, consumer code stays exhaustive.

```ts
import { Effect, Fiber, Console } from "effect";

const poller = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("[poll] tick");
    yield* Effect.sleep("30 millis");
  })
);

const condition: Effect.Effect<"stop"> = Effect.gen(function* () {
  yield* Effect.sleep("120 millis");
  return "stop" as const;
});

const program = Effect.gen(function* () {
  const fp = yield* Effect.fork(poller);
  const fc = yield* Effect.fork(condition);
  yield* Fiber.join(fc);
  yield* Fiber.interrupt(fp);
  yield* Console.log("[poller] halted by condition");
});

Effect.runPromise(program);
```

The condition fibre signals completion; the parent responds by interrupting the poller cleanly.

```ts
import { Effect, Data, Duration } from "effect";

class Cancelled extends Data.TaggedError("Cancelled")<{ readonly reason: string }> {}

const apiCall: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("200 millis");
  return "body";
});

const cancelAfter = (ms: number): Effect.Effect<never, Cancelled> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new Cancelled({ reason: `deadline ${ms}ms` }));
  });

// Equivalent of: controller.abort() after 150ms.
const program: Effect.Effect<string, Cancelled> = Effect.race(apiCall, cancelAfter(150));

Effect.runPromise(Effect.either(program)).then(console.log);
```

When the cancel branch wins, `apiCall`'s fibre is interrupted — fibres are natively cancellable, no AbortController needed.

```ts
import { Effect, Fiber, Console } from "effect";

const heartbeat = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("♥");
    yield* Effect.sleep("40 millis");
  })
);

const mainTask: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("130 millis");
  return "main done";
});

const program = Effect.gen(function* () {
  const hb = yield* Effect.fork(heartbeat);
  const result = yield* mainTask;
  yield* Fiber.interrupt(hb);
  return result;
});

Effect.runPromise(program).then(console.log);
```

The heartbeat fibre is explicitly interrupted; even if we forgot, the supervised fork would be cleaned up when the program exits.

```ts
import { Effect, Console, Duration } from "effect";

const candidate = (name: string, ms: number): Effect.Effect<string> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
